hooks/use-admin-counts.ts.content:
"use client"

import { useState, useEffect } from "react"
import { supabase } from "@/lib/supabase"

interface AdminCounts {
  totalAppointments: number
  pendingRequests: number
  triageEntries: number
  unreadChats: number
  todaysSessions: number
  thisWeekSessions: number
}

export function useAdminCounts() {
  const [counts, setCounts] = useState<AdminCounts>({
    totalAppointments: 0,
    pendingRequests: 0,
    triageEntries: 0,
    unreadChats: 0,
    todaysSessions: 0,
    thisWeekSessions: 0
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const fetchCounts = async () => {
    try {
      setError(null)

      // Get today's date range
      const today = new Date()
      today.setHours(0, 0, 0, 0)
      const tomorrow = new Date(today)
      tomorrow.setDate(tomorrow.getDate() + 1)

      // Get this week's date range (Monday to Sunday)
      const startOfWeek = new Date(today)
      const day = today.getDay()
      const diff = today.getDate() - day + (day === 0 ? -6 : 1) // Monday
      startOfWeek.setDate(diff)
      startOfWeek.setHours(0, 0, 0, 0)

      const endOfWeek = new Date(startOfWeek)
      endOfWeek.setDate(startOfWeek.getDate() + 7)

      // Fetch all counts in parallel
      const [
        appointmentsResult,
        pendingResult,
        triageResult,
        todayResult,
        weekResult
      ] = await Promise.all([
        // Total appointments (calendar badge)
        supabase
          .from('appointments')
          .select('id', { count: 'exact', head: true })
          .in('status', ['pending', 'confirmed']),

        // Pending requests (requests queue badge)
        supabase
          .from('appointments')
          .select('id', { count: 'exact', head: true })
          .eq('status', 'pending'),

        // AI triage entries (triage badge)
        supabase
          .from('ai_triage_entries')
          .select('id', { count: 'exact', head: true }),

        // Today's sessions (quick stats)
        supabase
          .from('appointments')
          .select('id', { count: 'exact', head: true })
          .eq('status', 'confirmed')
          .gte('date', today.toISOString().split('T')[0])
          .lt('date', tomorrow.toISOString().split('T')[0]),

        // This week's sessions (quick stats)
        supabase
          .from('appointments')
          .select('id', { count: 'exact', head: true })
          .eq('status', 'confirmed')
          .gte('date', startOfWeek.toISOString().split('T')[0])
          .lt('date', endOfWeek.toISOString().split('T')[0])
      ])

      setCounts({
        totalAppointments: appointmentsResult.count || 0,
        pendingRequests: pendingResult.count || 0,
        triageEntries: triageResult.count || 0,
        unreadChats: 0, // Placeholder - implement if chat system has unread tracking
        todaysSessions: todayResult.count || 0,
        thisWeekSessions: weekResult.count || 0
      })

    } catch (err) {
      console.error('Error fetching admin counts:', err)
      setError('Failed to fetch counts')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchCounts()
  }, [])

  return { counts, loading, error, refetch: fetchCounts }
}

hooks/use-mobile.ts.content:
import * as React from 'react'

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener('change', onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener('change', onChange)
  }, [])

  return !!isMobile
}

hooks/use-offline.ts.content:
import { useState, useEffect } from 'react'

interface UseOfflineOptions {
  autoRefresh?: boolean
  refreshInterval?: number
}

interface UseOfflineReturn {
  isOnline: boolean
  error: string | null
  lastUpdated: Date | null
  isRefreshing: boolean
  setError: (error: string | null) => void
  setLastUpdated: (date: Date | null) => void
  setIsRefreshing: (refreshing: boolean) => void
  executeWithOfflineCheck: <T>(fn: () => Promise<T>) => Promise<T | null>
}

export function useOffline(options: UseOfflineOptions = {}): UseOfflineReturn {
  const { autoRefresh = true, refreshInterval = 30000 } = options

  const [isOnline, setIsOnline] = useState(typeof navigator !== 'undefined' ? navigator.onLine : true)
  const [error, setError] = useState<string | null>(null)
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null)
  const [isRefreshing, setIsRefreshing] = useState(false)

  // Online/Offline detection
  useEffect(() => {
    const handleOnline = () => {
      setIsOnline(true)
      setError(null)
    }

    const handleOffline = () => {
      setIsOnline(false)
      setError("You're currently offline. Showing last available data.")
    }

    if (typeof window !== 'undefined') {
      window.addEventListener('online', handleOnline)
      window.addEventListener('offline', handleOffline)

      return () => {
        window.removeEventListener('online', handleOnline)
        window.removeEventListener('offline', handleOffline)
      }
    }
  }, [])

  // Function to execute async operations with offline checking
  const executeWithOfflineCheck = async <T,>(fn: () => Promise<T>): Promise<T | null> => {
    // Don't execute if offline
    if (typeof navigator !== 'undefined' && !navigator.onLine) {
      setError("You're currently offline. Showing last available data.")
      return null
    }

    setError(null)

    try {
      const result = await fn()
      setLastUpdated(new Date())
      setError(null)
      return result
    } catch (error) {
      console.error('Error executing function:', error)
      setError("Failed to load data. Please check your connection and try again.")
      setIsOnline(typeof navigator !== 'undefined' ? navigator.onLine : true)
      return null
    }
  }

  return {
    isOnline,
    error,
    lastUpdated,
    isRefreshing,
    setError,
    setLastUpdated,
    setIsRefreshing,
    executeWithOfflineCheck,
  }
}

// Hook for auto-refreshing data
export function useAutoRefresh(
  fetchFunction: () => Promise<void>,
  options: UseOfflineOptions = {}
) {
  const { refreshInterval = 30000 } = options
  const { isOnline, executeWithOfflineCheck } = useOffline(options)

  useEffect(() => {
    // Initial fetch
    executeWithOfflineCheck(fetchFunction)

    // Set up auto-refresh
    const interval = setInterval(() => {
      if (typeof navigator !== 'undefined' && navigator.onLine) {
        executeWithOfflineCheck(fetchFunction)
      }
    }, refreshInterval)

    return () => clearInterval(interval)
  }, [])

  return { isOnline, executeWithOfflineCheck }
}

hooks/use-toast.ts.content:
'use client'

// Inspired by react-hot-toast library
import * as React from 'react'

import type { ToastActionElement, ToastProps } from '@/components/ui/toast'

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: 'ADD_TOAST',
  UPDATE_TOAST: 'UPDATE_TOAST',
  DISMISS_TOAST: 'DISMISS_TOAST',
  REMOVE_TOAST: 'REMOVE_TOAST',
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType['ADD_TOAST']
      toast: ToasterToast
    }
  | {
      type: ActionType['UPDATE_TOAST']
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType['DISMISS_TOAST']
      toastId?: ToasterToast['id']
    }
  | {
      type: ActionType['REMOVE_TOAST']
      toastId?: ToasterToast['id']
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: 'REMOVE_TOAST',
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case 'ADD_TOAST':
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case 'UPDATE_TOAST':
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t,
        ),
      }

    case 'DISMISS_TOAST': {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t,
        ),
      }
    }
    case 'REMOVE_TOAST':
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, 'id'>

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: 'UPDATE_TOAST',
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: 'DISMISS_TOAST', toastId: id })

  dispatch({
    type: 'ADD_TOAST',
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: 'DISMISS_TOAST', toastId }),
  }
}

export { useToast, toast }

lib/ai-triage-utils.ts.content:
"use client"

import { supabase } from "@/lib/supabase"
import type { Database } from "@/lib/types/database"

export interface StudentTriageData {
  name: string
  email: string
  phone: string
  purpose: string
}

export interface TriageResult {
  decision: 'approved' | 'declined' | 'uncertain'
  reasoning: string
  confidence: number
}

export interface TriageResponse {
  success: boolean
  result: TriageResult
  error?: string
  student?: {
    name: string
    email: string
  }
}

/**
 * Call the AI triage edge function to evaluate a student's mentorship request
 */
export const evaluateStudentRequest = async (studentData: StudentTriageData): Promise<TriageResponse> => {
  try {
    console.log('🤖 Sending student request for AI evaluation:', studentData.name)

    // Try direct fetch first as a fallback
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
    const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY

    if (!supabaseUrl || !supabaseKey) {
      throw new Error('Supabase configuration missing')
    }

    console.log('🔗 Using direct fetch to Edge Function...')
    const response = await fetch(`${supabaseUrl}/functions/v1/ai-triage-student`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${supabaseKey}`,
        'apikey': supabaseKey
      },
      body: JSON.stringify({
        name: studentData.name,
        email: studentData.email,
        phone: studentData.phone,
        purpose: studentData.purpose
      })
    })

    console.log('🔍 Direct fetch response status:', response.status)
    console.log('🔍 Direct fetch response headers:', Object.fromEntries(response.headers.entries()))

    if (!response.ok) {
      const errorText = await response.text()
      console.error('❌ Direct fetch failed:', response.status, errorText)
      throw new Error(`Edge Function failed: ${response.status} - ${errorText}`)
    }

    const data = await response.json()
    console.log('✅ Direct fetch succeeded:', data)

    if (!data) {
      console.error('No data returned from Edge Function')
      throw new Error('No response from AI triage service')
    }

    // Validate response structure
    if (!data.success && !data.result) {
      console.error('❌ Invalid response structure:', data)
      throw new Error('Invalid response from AI service')
    }

    console.log('✅ AI Triage completed:', data.result?.decision)
    console.log('📊 Full response:', data)
    return data as TriageResponse

  } catch (error) {
    console.error('❌ AI triage evaluation failed:', error)

    // More detailed error logging
    if (error instanceof Error) {
      console.error('Error name:', error.name)
      console.error('Error message:', error.message)
      console.error('Error stack:', error.stack)
    }

    const errorMessage = error instanceof Error ? error.message : 'AI evaluation failed'

    // Return a fallback response to keep user flow working
    return {
      success: false,
      error: errorMessage,
      result: {
        decision: 'uncertain',
        reasoning: 'AI evaluation temporarily unavailable. Your request will be reviewed manually by our team.',
        confidence: 0.5
      }
    }
  }
}

/**
 * Save triage result to database for admin review and analytics
 */
export const saveTriageResult = async (
  studentData: StudentTriageData, 
  triageResult: TriageResult
) => {
  try {
    console.log('💾 Saving triage result to database')

    const insertData = {
      student_name: studentData.name,
      student_email: studentData.email,
      student_phone: studentData.phone,
      purpose: studentData.purpose,
      ai_decision: triageResult.decision,
      ai_reasoning: triageResult.reasoning,
      ai_confidence: triageResult.confidence,
      manual_review: false
    }

    const { error } = await supabase
      .from('student_triage_log')
      .insert(insertData as any)

    if (error) {
      console.error('Error saving triage result:', error)
      // Don't throw error - this is just for logging
    } else {
      console.log('✅ Triage result saved to database')
    }

  } catch (error) {
    console.error('Failed to save triage result:', error)
    // Don't throw error - this is just for logging
  }
}

/**
 * Format the AI reasoning for display to users
 */
export const formatTriageReasoning = (reasoning: string): string => {
  // Clean up the reasoning text for user display
  return reasoning
    .replace(/✅|❌|🤔/g, '') // Remove emojis
    .replace(/\s+/g, ' ') // Normalize whitespace
    .trim()
}

/**
 * Get user-friendly message based on triage decision
 */
export const getTriageMessage = (decision: 'approved' | 'declined' | 'uncertain'): string => {
  switch (decision) {
    case 'approved':
      return 'Great! Your request has been approved. You can now select a time slot for your free mentorship session.'

    case 'declined':
      return 'Thank you for your interest. Due to limited availability and session focus, this request cannot be approved for a free session. You can still get guidance through our paid consultation options.'

    case 'uncertain':
      return 'Your request is under review. Our team will evaluate it manually and get back to you via email within 24 hours.'

    default:
      return 'Your request is being processed. Please check back later.'
  }
}

lib/calendar-utils.ts.content:
export const formatTime = (time24: string) => {
  const [hours, minutes] = time24.split(':')
  const hour12 = parseInt(hours) % 12 || 12
  const ampm = parseInt(hours) >= 12 ? 'PM' : 'AM'
  return `${hour12}:${minutes} ${ampm}`
}

export const formatDate = (date: string) => {
  return new Date(date).toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric'
  })
}

export interface TimeSlot {
  id: string
  date: string
  time: string
  is_available: boolean
  slot_type: "business" | "student" | "both"
  session_type: "free" | "paid"
}

export interface BookingStats {
  totalBookings: number
  pendingApprovals: number
}

export const fetchTimeSlots = async (
  slotTypeFilter: string[],
  sessionTypeFilter?: "free" | "paid"
) => {
  try {
    const { supabase } = await import("@/lib/supabase")

    const today = new Date().toISOString().split('T')[0]

    let query = supabase
      .from('time_slots')
      .select('*')
      .gte('date', today)
      .in('slot_type', slotTypeFilter)
      .order('date', { ascending: true })
      .order('time', { ascending: true })

    if (sessionTypeFilter) {
      query = query.eq('session_type', sessionTypeFilter)
    }

    const { data: slots, error } = await query

    if (error) {
      console.error('Error fetching slots:', error)
      return []
    }

    return slots || []
  } catch (error) {
    console.error('Error:', error)
    return []
  }
}

export const fetchBookingStats = async (type: 'business' | 'student') => {
  try {
    const { supabase } = await import("@/lib/supabase")

    const today = new Date()
    const weekStart = new Date(today)
    weekStart.setDate(today.getDate() - today.getDay())

    const { data: appointments, error } = await supabase
      .from('appointments')
      .select('*')
      .gte('date', weekStart.toISOString().split('T')[0])
      .eq('type', type)

    if (error) {
      console.error('Error fetching appointments:', error)
      return { totalBookings: 0, pendingApprovals: 0 }
    }

    const pending = appointments?.filter(a => a.status === 'pending') || []

    return {
      totalBookings: appointments?.length || 0,
      pendingApprovals: pending.length
    }
  } catch (error) {
    console.error('Error:', error)
    return { totalBookings: 0, pendingApprovals: 0 }
  }
}

