import { serve } from "https://deno.land/std@0.168.0/http/server.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS"
};

interface BookingEmailRequest {
  // Client notification
  clientEmail?: {
    to: string
    name: string
    date: string
    time: string
    meetingType: 'online' | 'in-person'
    meetingUrl?: string
    venueAddress?: string
    sessionType: 'free' | 'paid'
    appointmentType: 'business' | 'student' | 'in-person'
    status: 'confirmed' | 'pending'
  }

  // Admin notification
  adminEmail?: {
    bookingType: 'business' | 'student' | 'in-person'
    clientName: string
    clientEmail: string
    clientPhone: string
    date?: string
    time?: string
    purpose: string
    sessionType: 'free' | 'paid'
    status: 'confirmed' | 'pending'
  }
}

function generateClientConfirmationHTML(data: any): string {
  const isConfirmed = data.status === 'confirmed';
  const statusText = isConfirmed ? 'Confirmed' : 'Pending Approval';
  const statusColor = isConfirmed ? '#10b981' : '#f59e0b';

  return `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${data.appointmentType.charAt(0).toUpperCase() + data.appointmentType.slice(1)} Session ${statusText}</title>
    <style>
        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
            background-color: #f8fafc;
        }
        .container {
            background: white;
            border-radius: 12px;
            padding: 32px;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
        }
        .header {
            text-align: center;
            margin-bottom: 32px;
            padding-bottom: 24px;
            border-bottom: 2px solid #e2e8f0;
        }
        .logo {
            font-size: 24px;
            font-weight: bold;
            color: #1e40af;
            margin-bottom: 8px;
        }
        .subtitle {
            color: #64748b;
            font-size: 14px;
        }
        .status-badge {
            display: inline-block;
            padding: 8px 16px;
            border-radius: 20px;
            font-weight: 600;
            font-size: 14px;
            margin: 16px 0;
            background-color: ${statusColor};
            color: white;
        }
        .meeting-details {
            background-color: #f1f5f9;
            border-radius: 8px;
            padding: 24px;
            margin: 24px 0;
        }
        .detail-row {
            display: flex;
            justify-content: space-between;
            margin-bottom: 12px;
            padding-bottom: 8px;
            border-bottom: 1px solid #e2e8f0;
        }
        .detail-row:last-child {
            border-bottom: none;
            margin-bottom: 0;
        }
        .detail-label {
            font-weight: 600;
            color: #475569;
        }
        .detail-value {
            color: #1e293b;
        }
        .meeting-link {
            background-color: #ecfdf5;
            border: 1px solid #10b981;
            border-radius: 8px;
            padding: 16px;
            margin: 16px 0;
            text-align: center;
        }
        .meeting-link a {
            color: #10b981;
            text-decoration: none;
            font-weight: 600;
        }
        .footer {
            margin-top: 32px;
            text-align: center;
            font-size: 12px;
            color: #64748b;
            padding-top: 24px;
            border-top: 1px solid #e2e8f0;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <div class="logo">Xeven Solutions</div>
            <div class="subtitle">AI-Driven Business Solutions</div>
            <div class="status-badge">${statusText}</div>
        </div>

        <h2>Hello ${data.name},</h2>

        ${isConfirmed
          ? `<p>Your ${data.appointmentType} session has been confirmed! Here are the details:</p>`
          : `<p>Thank you for your ${data.appointmentType} session request. It is currently pending approval and you will receive an update soon.</p>`
        }

        <div class="meeting-details">
            <div class="detail-row">
                <span class="detail-label">Session Type:</span>
                <span class="detail-value">${data.sessionType === 'paid' ? 'Paid' : 'Free'} ${data.appointmentType.charAt(0).toUpperCase() + data.appointmentType.slice(1)} Session</span>
            </div>
            ${data.date ? `
            <div class="detail-row">
                <span class="detail-label">Date & Time:</span>
                <span class="detail-value">${new Date(data.date).toLocaleDateString('en-US', {
                    weekday: 'long',
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric'
                })} at ${data.time}</span>
            </div>
            ` : ''}
            <div class="detail-row">
                <span class="detail-label">Meeting Type:</span>
                <span class="detail-value">${data.meetingType === 'online' ? 'Online (Video Call)' : 'In-Person'}</span>
